SELECT [Reserv__Assign_ Line].[Trademark Code], [Reserv__Assign_ Line].[Selling Season Code] AS [Season Code], [Geographical Zone].Description AS GeoZone2Description, Salesperson_Purchaser.Name AS SalesPersonname, [Sales Line].[Sell-to Customer No_], Customer.Name AS CustomerName, [Sales Header].[Ship-to City], Customer.[Reservation Priority], [Sales Header].[Payment Method Code], [Sales Header].[Payment Terms Code], [Reserv__Assign_ Line].[Sales Document No_] AS [Document No_], [Reserv__Assign_ Line].[Sales Line No_] AS [Line No_], Val([Reserved_Assigned Quantity]) AS QTY, IIf([source type]=0,"PRE_GIAC",IIf([source type]=1,"PRE_ACQ","PRE_TRS")) AS CAT, [Reserv__Assign_ Link].[Model Item No_], [Reserv__Assign_ Link].[Variable Code 01] AS Color, [Reserv__Assign_ Link].[Variable Code 02] AS [Size], [Sales Line].[Requested Delivery Date], [Reserv__Assign_ Link].[Date Reservation], [Reserv__Assign_ Link].[Source Type], [Reserv__Assign_ Link].[Source Document No_], [Reserv__Assign_ Line].[Location Code] AS MagVend, [Reserv__Assign_ Link].[Location Code] AS MagSource, Item.[Vendor No_], Vendor.Name AS VendorName
FROM ((((((([Reserv__Assign_ Line] LEFT JOIN [Reserv__Assign_ Link] ON ([Reserv__Assign_ Line].[Line No_] = [Reserv__Assign_ Link].[Line No_]) AND ([Reserv__Assign_ Line].[Batch Name] = [Reserv__Assign_ Link].[Batch Name]) AND ([Reserv__Assign_ Line].[Template Name] = [Reserv__Assign_ Link].[Template Name]) AND ([Reserv__Assign_ Line].[Reserv__Assign_ Type] = [Reserv__Assign_ Link].[Reserv__Assign_ Type])) LEFT JOIN Item ON [Reserv__Assign_ Link].No_ = Item.No_) LEFT JOIN [Sales Line] ON ([Reserv__Assign_ Line].[Sales Line No_] = [Sales Line].[Line No_]) AND ([Reserv__Assign_ Line].[Sales Document No_] = [Sales Line].[Document No_])) LEFT JOIN Vendor ON Item.[Vendor No_] = Vendor.No_) LEFT JOIN Customer ON [Sales Line].[Sell-to Customer No_] = Customer.No_) LEFT JOIN [Geographical Zone] ON Customer.[Geographical Zone 2] = [Geographical Zone].Code) LEFT JOIN [Sales Header] ON [Sales Line].[Document No_] = [Sales Header].No_) LEFT JOIN Salesperson_Purchaser ON [Sales Header].[Salesperson Code] = Salesperson_Purchaser.Code
WHERE ((([Reserv__Assign_ Line].[Trademark Code])=[Forms]![principale]![FiltroMarchioSourcing]) AND (([Reserv__Assign_ Line].[Selling Season Code])=[Forms]![principale]![FiltroStagioneSourcing]) AND ((Val([Reserved_Assigned Quantity]))<>0) AND (([Reserv__Assign_ Line].Type)=2));

